SELECT COUNT(*) AS total_exports
FROM export_data
WHERE country_id = (SELECT country_id FROM countries WHERE country_name = 'Hong Kong');

SELECT COUNT(export_id) AS total_exports
FROM export_data
WHERE country_id = 1;

SELECT MAX(trade_value_usd) AS max_trade_value
FROM export_data
WHERE country_id = 1 AND year = 2023;

SELECT analysis_type
FROM data_analytics
WHERE export_id = 2;

SELECT COUNT(api_key_id) AS active_api_keys_count
FROM api_keys
WHERE is_active = 1;
